import{_ as e,o,c as a,ag as l}from"./chunks/framework.ePeAWSvT.js";const _=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"2.5시간 후, AI 비서가 생깁니다","text":"Claude Code 실전 입문","tagline":"코딩 경험 0이어도 OK · 마케터·기획자·대표님 환영 · 최주원이 옆에서 같이 합니다","actions":[{"theme":"brand","text":"사전준비 시작하기 →","link":"/사전가이드"},{"theme":"alt","text":"커리큘럼 보기","link":"/워크샵커리큘럼"}]},"features":[{"title":"🙋 완전 초보자 OK","details":"터미널이 뭔지 몰라도 됩니다. \\"코딩\\"이라는 단어가 낯설어도 됩니다. 처음부터 끝까지 하나씩 같이 합니다."},{"title":"⚡ 2.5시간, 딱 그만큼","details":"오늘 이 자리가 끝나면 AI가 내 반복 업무를 대신하게 됩니다. 배우고 끝나는 게 아니라, 실제로 작동하는 결과물을 들고 갑니다."},{"title":"🛠️ 듣는 강의가 아닙니다","details":"직접 만들어봅니다. 내 업무에 맞는 자동화 명령어를 오늘 실습 시간에 완성합니다. 손으로 만들어야 기억에 남습니다."}]},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),s={name:"index.md"};function i(n,t,r,d,p,c){return o(),a("div",null,[...t[0]||(t[0]=[l('<h2 id="오늘의-약속" tabindex="-1">오늘의 약속 <a class="header-anchor" href="#오늘의-약속" aria-label="Permalink to &quot;오늘의 약속&quot;">​</a></h2><p>이 워크샵이 끝나면 여러분은 이 세 가지를 갖게 됩니다:</p><ol><li><strong>Claude Code가 뭔지 설명할 수 있다</strong> — 친구나 동료에게 &quot;이런 거야&quot;라고 자신 있게 말할 수 있을 정도로</li><li><strong>나만의 스킬(자동화 명령어) 1개를 직접 만든다</strong> — 실제로 작동하는 것을, 내 손으로</li><li><strong>내 업무를 자동화하는 설계서를 완성한다</strong> — 오늘 이후 혼자서도 만들 수 있는 나만의 지도</li></ol><div class="tip custom-block"><p class="custom-block-title">걱정하지 마세요, 정말로</p><p>코딩 경험이 전혀 없어도 됩니다. &quot;터미널&quot;이 뭔지 몰라도 됩니다. &quot;AI&quot;라는 단어가 아직 어색해도 됩니다. 오늘은 그냥 따라오기만 하면 됩니다. 최주원이 옆에서 같이 합니다.</p></div><hr><h2 id="진행자-소개" tabindex="-1">진행자 소개 <a class="header-anchor" href="#진행자-소개" aria-label="Permalink to &quot;진행자 소개&quot;">​</a></h2><p><strong>최주원 (AI JOOWON)</strong></p><p>AI를 여러 사람에게 알려주는 AI 인플루언서입니다. Claude Code, n8n, MCP 등 최신 AI 도구를 직접 사용하며, 그 실전 경험을 콘텐츠로 공유합니다.</p><p>이론보다 <strong>&quot;진짜 써보기&quot;</strong> 를 중요하게 생각합니다. 오늘 이 자리도 그 연장선입니다.</p><p>같이 해봅시다.</p><div class="info custom-block"><p class="custom-block-title">사전준비부터 시작할게요</p><p>워크샵 전날까지 아래 버튼을 눌러 사전준비를 완료해 오세요. 15~30분이면 충분합니다.</p><p>→ <a href="/사전가이드">사전가이드 바로가기</a></p></div>',11)])])}const m=e(s,[["render",i]]);export{_ as __pageData,m as default};
